//// Convolution Functions
int32_t riscv_nn_conv_HWC_s8_s8_s8_RGB_sft_bias(const q7_t * in_tensor,
                               const uint16_t in_tensor_dim,
                               const q7_t * ker_weight,
                               const uint16_t out_tensor_ch,
                               const uint16_t ker_dim,
                               const uint16_t pad,
                               const uint16_t stride,
                               const q7_t * bias,
                               const uint16_t bias_lshift,
                               const uint16_t out_rshift,
                               q7_t * out_tensor,
                               const uint16_t out_tensor_dim,
                               q15_t * in_tmp_buf,
                               q7_t * tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;
    q7_t *pBuffer = (q7_t *)in_tmp_buf;
    q7_t *pOut = out_tensor;
    q7_t *pBufferB = tmp_buf;
    uint32_t i;

    uint16_t totalsize = 3 * ker_dim * ker_dim;
    for (i = 0; i < out_tensor_ch; i++)
    {
        uint32_t size = totalsize;
        while (size > 0)
        {
            int32_t vl;
            vl = __riscv_vsetvl_e8m1(size);
            vint8m1_t vWt_tmp = __riscv_vle8_v_i8m1(wt_tmp, vl);
            __riscv_vse8(pBufferB, vWt_tmp, vl);
            wt_tmp += vl;
            pBufferB += vl;
            size -= vl;
        }
        *pBufferB++ = 0;
    }

    uint32_t buf_len = (3 * ker_dim * ker_dim + 1);
    unsigned vl;
    vl = __riscv_vsetvl_e8m1(buf_len);
    vint8m1_t vZero = __riscv_vand(__riscv_vundefined_i8m1(), 0, vl);   //zero

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            //init in_tmp_buf
            uint32_t len = buf_len;
            q7_t *pBuffer2 = pBuffer;
            while (len > 0)
            {
                vl = __riscv_vsetvl_e8m1(len);
                __riscv_vse8(pBuffer2, vZero, vl);
                len -= vl;
                pBuffer2 += vl;
            }

            // if (i_ker_y < 0)
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            int16_t bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim) ? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
            for (; i_ker_y < bound_y; i_ker_y++)
            {
                // if (i_ker_x < 0)
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
                {
                    pBuffer += 3;
                }

                uint16_t bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim) ? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                uint32_t loop = (bound_x - i_ker_x) * 3;
                i_ker_x = bound_x;
                while (loop > 0)
                {
                    vl = __riscv_vsetvl_e8m1(loop);
                    vint8m1_t vpPixel = __riscv_vle8_v_i8m1(pPixel, vl);
                    __riscv_vse8(pBuffer, vpPixel, vl);
                    pPixel += vl;
                    pBuffer += vl;
                    loop -= vl;
                }

                // if (i_ker_x >= in_tensor_dim)
                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    pBuffer += 3;
                }
            }

            // if (i_ker_y >= in_tensor_dim)
            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }
            pBuffer++;

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q7((q7_t *)tmp_buf, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, bias_lshift, out_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        unsigned vl;
        const q7_t *p_wt = ker_weight;
        int       i;
        uint16_t  colCnt = 3 * ker_dim * ker_dim;
        // long vlenb = NDS_VEC_CSR_GET_VLENB();

        vl = __riscv_vsetvl_e32m1(1);
        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum

        for (i = 0; i < out_tensor_ch; i++)
        {
            q7_t      *p_in = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //clear v0~v7
            vl = __riscv_vsetvl_e32m8(colCnt);
            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);

            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
            // {
            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            //     //load src1
            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
            //     //load src2
            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
            //     //bump pointers and update loop counter
            //     colCnt2 -= vl;
            //     p_wt += vl;
            //     p_in += vl;
            //     //set the proper avl/SEW/LMUL values for vd4dot
            //     vl >>= 2;
            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            //     //acc += src1 * src2
            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            // }

            //extra process for the case of vd4dot's avl is not a mutiple of 4
            while(colCnt2 > 0)
            {
                //clean one of the dot product source
                vl = __riscv_vsetvlmax_e8m8();
                vint8m8_t vP_wt_i8m8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);

                vl = __riscv_vsetvl_e8m8(colCnt2);
                //load src1
                vP_wt_i8m8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8m8, p_wt, vl);
                //load src2
                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                //remember to deal with the avl of vd4dot is not a multiple of 4 case
                vl = __riscv_vsetvl_e32m8(vl);
                //acc += src1 * src2
                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
            }

            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);

            //add bias back
            vl = __riscv_vsetvl_e32m1(1);
            vint8mf4_t vBias_i8mf4 = __riscv_vle8_v_i8mf4(bias, vl);
            vint32m1_t vBias_i32m1 = __riscv_vsext_vf4(vBias_i8mf4, vl);
            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);

            //scale down, clip and store the results
            vl = __riscv_vsetvl_e16mf2(1);
            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
            vl = __riscv_vsetvl_e8mf4(1);
            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
            __riscv_vse8(pOut, vSum_i8mf4, vl);

            bias += vl;
            pOut += vl;
        }
    }
#elif (NDS_VEC_RVV_VERSION >= 100)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;
        /* basically each time it process 4 entries */
        uint16_t colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
        vl = __riscv_vsetvl_e32m8(colCnt);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
            q7_t *pB = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //init
            vint32m1_t vBias = __riscv_vmv_s_x_i32m1(sum, vl);
            //clear v8~v15 (acc)
            vint32m8_t vAcc = __riscv_vundefined_i32m8();
            vAcc = __riscv_vand_tu(vAcc, vAcc, 0, vl);

            while (colCnt2 > 0)
            {
                vl = __riscv_vsetvl_e8m2(colCnt2);
                vint8m2_t vPa_i8 = __riscv_vundefined_i8m2();
                vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
                vPa_i8 = __riscv_vle8_tu(vPa_i8, pA, vl);
                vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
                vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vPa_i8, vPb_i8, vl);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
            vint32m1_t vAcc_sum = __riscv_vredsum(vAcc, vBias, vl);
            //move vr results to gpr
            sum = __riscv_vmv_x(vAcc_sum);

            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> out_rshift), 8);
        }
    }
#endif
